TARGET_FUNCTIONS = ['upload_file', 'upload_partner_file', 'export_grouped_csv', 'export_hierarchy_csv', 'delete_grouped_upload']

MODULE_SOURCE = 'async def upload_file(request: Request, buyer: str = Form(...), file: UploadFile = File(...), period_view: str = Form(default="current"), period_label: str = Form(default=""), brand: str = Form(default=""), manager: str = Form(default=""), geo: str = Form(default=""), ad_name: str = Form(default=""), adset_name: str = Form(default=""), creative: str = Form(default=""), search: str = Form(default=""), sort_by: str = Form(default="spend"), order: str = Form(default="desc")):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    require_any_role(user, "superadmin", "admin")\n    ensure_fb_table()\n    original_name = file.filename or ""\n    ext = os.path.splitext(original_name)[1].lower() or ".csv"\n    filename = f"temp_{uuid.uuid4()}{ext}"\n\n    try:\n        with open(filename, "wb") as buffer:\n            shutil.copyfileobj(file.file, buffer)\n\n        if ext in [".xlsx", ".xls"]:\n            df = pd.read_excel(filename)\n        else:\n            try:\n                df = pd.read_csv(filename)\n            except Exception:\n                df = pd.read_csv(filename, sep=";")\n\n        detected_period = detect_fb_upload_period(df) or {}\n        upload_period_label = safe_text(detected_period.get("period_label")) or get_current_period_label()\n        source_name = build_fb_source_name(buyer.strip(), detected_period)\n        rows_to_insert = parse_uploaded_dataframe(\n            df,\n            buyer.strip(),\n            source_name=source_name,\n            period_label=upload_period_label,\n            period_date_start=safe_text(detected_period.get("date_start")),\n            period_date_end=safe_text(detected_period.get("date_end")),\n        )\n        if not rows_to_insert:\n            return RedirectResponse(url="/grouped?message=FB+upload+is+empty", status_code=303)\n\n        db = SessionLocal()\n        try:\n            db.query(FBRow).filter(FBRow.source_name == source_name).delete()\n            db.commit()\n            for item in rows_to_insert:\n                db.add(item)\n            db.commit()\n        finally:\n            db.close()\n\n        redirect_period_view = safe_text(period_view) or "period"\n        redirect_period_label = safe_text(period_label)\n        redirect_url = (\n            f"/grouped?buyer={quote_plus(safe_text(buyer))}"\n            f"&brand={quote_plus(safe_text(brand))}"\n            f"&manager={quote_plus(safe_text(manager))}"\n            f"&geo={quote_plus(safe_text(geo))}"\n            f"&ad_name={quote_plus(safe_text(ad_name))}"\n            f"&adset_name={quote_plus(safe_text(adset_name))}"\n            f"&creative={quote_plus(safe_text(creative))}"\n            f"&search={quote_plus(safe_text(search))}"\n            f"&period_view={quote_plus(redirect_period_view)}"\n            f"&period_label={quote_plus(redirect_period_label)}"\n            f"&source_name={quote_plus(source_name)}"\n            f"&sort_by={quote_plus(safe_text(sort_by) or \'spend\')}"\n            f"&order={quote_plus(safe_text(order) or \'desc\')}"\n        )\n        return RedirectResponse(url=redirect_url, status_code=303)\n    finally:\n        if os.path.exists(filename):\n            os.remove(filename)\n\nasync def upload_partner_file(request: Request, file: UploadFile = File(...), cabinet_name: str = Form(default="")):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    require_any_role(user, "superadmin", "admin")\n    ensure_partner_table()\n    original_name = file.filename or "partner.csv"\n    ext = os.path.splitext(original_name)[1].lower() or ".csv"\n    filename = f"temp_partner_{uuid.uuid4()}{ext}"\n    try:\n        with open(filename, "wb") as buffer:\n            shutil.copyfileobj(file.file, buffer)\n        df = read_partner_uploaded_dataframe(filename, ext)\n        clean_cabinet_name = safe_text(cabinet_name)\n        detected_period = detect_partner_upload_period(df, partner_platform="1xbet", fallback_text=original_name)\n        if not detected_period:\n            return HTMLResponse(partner_report_page_html(user, get_partner_rows_by_period(""), error_text="Could not determine upload period from the file header or filename."), status_code=400)\n        source_name = original_name if not clean_cabinet_name else build_partner_source_name(\n            detected_period["date_start"],\n            detected_period["date_end"],\n            prefix=clean_cabinet_name.replace("|", "/"),\n        )\n        replace_partner_rows(\n            source_name,\n            parse_partner_dataframe(\n                df,\n                source_name=source_name,\n                cabinet_name=clean_cabinet_name,\n                upload_period_data=detected_period,\n            ),\n        )\n        return RedirectResponse(url="/partner-report?message=Upload+saved", status_code=303)\n    finally:\n        if os.path.exists(filename):\n            os.remove(filename)\n\ndef export_grouped_csv(\n    request: Request,\n    buyer: str = Query(default=""),\n    brand: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    ad_name: str = Query(default=""),\n    adset_name: str = Query(default=""),\n    creative: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="current"),\n    period_label: str = Query(default=""),\n    source_name: str = Query(default=""),\n    sort_by: str = Query(default="spend"),\n    order: str = Query(default="desc"),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    require_any_role(user, "superadmin", "admin")\n    buyer = resolve_effective_buyer(user, buyer)\n    effective_period_label = resolve_period_label(period_view, period_label) or get_current_period_label()\n    rows = aggregate_grouped_rows(get_filtered_data(\n        buyer,\n        manager,\n        geo,\n        brand,\n        search,\n        effective_period_label,\n        source_name,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n    ))\n    reverse = order.lower() != "asc"\n    rows.sort(key=lambda x: x.get(sort_by, 0) if x.get(sort_by) is not None else 0, reverse=reverse)\n\n    output = io.StringIO()\n    writer = csv.writer(output)\n    writer.writerow([\n        "Название объявления",\n        "Просмотры материалов",\n        "Цена за просмотр контента",\n        "Клики по ссылке",\n        "CPC (цена за клик по ссылке)",\n        "Частота",\n        "CTR (все)",\n        "Лиды",\n        "Цена за лид",\n        "Подписки",\n        "Цена за платную подписку",\n        "Контакты",\n        "Цена за контакт",\n        "Завершенные регистрации",\n        "Цена за завершенную регистрацию",\n        "Покупки",\n        "Цена за покупку",\n        "Сумма затрат",\n        "Идентификатор аккаунта",\n        "Название группы объявлений",\n        "Budget",\n        "Название компании",\n    ])\n    for row in rows:\n        writer.writerow([\n            row["ad_name"],\n            format_int_or_float(row["material_views"]),\n            format_money(row["cost_per_content_view"]),\n            format_int_or_float(row["clicks"]),\n            format_money(row["cpc_real"]),\n            format_int_or_float(row["frequency"]),\n            format_percent(row["ctr"]),\n            format_int_or_float(row["leads"]),\n            format_money(row["cpl_real"]),\n            format_int_or_float(row["paid_subscriptions"]),\n            format_money(row["cost_per_paid_subscription"]),\n            format_int_or_float(row["contacts"]),\n            format_money(row["cost_per_contact"]),\n            format_int_or_float(row["reg"]),\n            format_money(row["cost_per_completed_registration"]),\n            format_int_or_float(row["ftd"]),\n            format_money(row["cpa_real"]),\n            format_money(row["spend"]),\n            row["account_id"],\n            row["adset_name"],\n            format_money(row["budget"]),\n            row["campaign_name"],\n        ])\n    output.seek(0)\n    filename = f"fb_export_{effective_period_label.replace(\' \', \'_\')}.csv"\n    return StreamingResponse(iter([output.getvalue()]), media_type="text/csv; charset=utf-8", headers={"Content-Disposition": f"attachment; filename={filename}"})\n\ndef export_hierarchy_csv(\n    request: Request,\n    buyer: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    offer: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="period"),\n    period_label: str = Query(default=""),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    require_any_role(user, "superadmin", "admin")\n    buyer = resolve_effective_buyer(user, buyer)\n    effective_period_label = resolve_period_label(period_view, period_label) or get_current_period_label()\n    rows = enrich_statistic_rows(\n        aggregate_grouped_rows(get_filtered_data(buyer, manager, geo, offer, search, period_label=effective_period_label)),\n        period_label=effective_period_label,\n    )\n    output = io.StringIO()\n    writer = csv.writer(output)\n    writer.writerow(["Geo", "Platform", "Manager", "Offer", "Creative", "Ad Name", "Leads", "Reg", "FB FTD", "Chatterfy", "Total FTD", "Qual FTD", "Rate", "Spend", "Income", "Profit", "ROI"])\n    for row in rows:\n        writer.writerow([\n            row["geo"], row["platform"], row["manager"], row["offer"], row["creative"], row["ad_name"],\n            format_int_or_float(row["leads"]), format_int_or_float(row["reg"]), format_int_or_float(row["ftd"]),\n            format_int_or_float(row.get("stat_chatterfy", 0)),\n            format_int_or_float(row.get("stat_total_ftd", 0)), format_int_or_float(row.get("stat_qual_ftd", 0)), format_money(row.get("stat_rate", 0)),\n            format_money(row["spend"]), format_money(row.get("stat_income", 0)), format_money(row.get("stat_profit", 0)), format_percent(row.get("stat_roi", 0)),\n        ])\n    output.seek(0)\n    return StreamingResponse(iter([output.getvalue()]), media_type="text/csv; charset=utf-8", headers={"Content-Disposition": "attachment; filename=teambead_statistic.csv"})\n\ndef delete_grouped_upload(\n    request: Request,\n    source_name: str = Form(default=""),\n    buyer: str = Form(default=""),\n    brand: str = Form(default=""),\n    manager: str = Form(default=""),\n    geo: str = Form(default=""),\n    ad_name: str = Form(default=""),\n    adset_name: str = Form(default=""),\n    creative: str = Form(default=""),\n    search: str = Form(default=""),\n    period_view: str = Form(default="current"),\n    period_label: str = Form(default=""),\n    sort_by: str = Form(default="spend"),\n    order: str = Form(default="desc"),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    require_any_role(user, "superadmin", "admin")\n    ensure_fb_table()\n    clean_source_name = safe_text(source_name)\n    if clean_source_name:\n        db = SessionLocal()\n        try:\n            db.query(FBRow).filter(FBRow.source_name == clean_source_name).delete()\n            db.commit()\n        finally:\n            db.close()\n    redirect_url = (\n        f"/grouped?buyer={quote_plus(safe_text(buyer))}"\n        f"&brand={quote_plus(safe_text(brand))}"\n        f"&manager={quote_plus(safe_text(manager))}"\n        f"&geo={quote_plus(safe_text(geo))}"\n        f"&ad_name={quote_plus(safe_text(ad_name))}"\n        f"&adset_name={quote_plus(safe_text(adset_name))}"\n        f"&creative={quote_plus(safe_text(creative))}"\n        f"&search={quote_plus(safe_text(search))}"\n        f"&period_view={quote_plus(safe_text(period_view) or \'period\')}"\n        f"&period_label={quote_plus(safe_text(period_label))}"\n        f"&sort_by={quote_plus(safe_text(sort_by) or \'spend\')}"\n        f"&order={quote_plus(safe_text(order) or \'desc\')}"\n    )\n    return RedirectResponse(url=redirect_url, status_code=303)\n\n'


def bind_domain_actions(ctx):
    scope = dict(ctx)
    exec(MODULE_SOURCE, scope)
    return {name: scope[name] for name in TARGET_FUNCTIONS}
